<section class="dashboard-section"><div class="section-header"><div><span class="section-kicker">Catalogue & Stock</span><h2>Produits et articles</h2><p class="ui-page-intro">Suivez les prix, les coûts et les niveaux de stock du catalogue commercial.</p></div><a class="btn btn-primary" href="<?= url('products/create'); ?>"><i class="bi bi-plus-circle"></i> Ajouter un produit</a></div><?php if ($m=Session::flash('success')): ?><div class="alert alert-success"><?= e($m); ?></div><?php endif; ?></section>
<section class="panel"><div class="panel-header"><div><span class="section-kicker">Catalogue</span><h3>Liste des produits</h3></div><span class="badge badge-neutral"><?= count($products); ?> produits</span></div><div class="filters-bar"><label>Recherche <input type="search" data-table-search data-target="#products-table" placeholder="SKU, produit ou catégorie"></label></div><div class="table-responsive"><table class="data-table" id="products-table"><thead><tr><th>SKU</th><th>Produit</th><th>Catégorie</th><th class="text-right">Coût d’achat</th><th class="text-right">Prix de vente</th><th class="text-right">Stock</th><th>Statut</th></tr></thead><tbody><?php foreach($products as $p): ?><tr><td><strong><?= e($p['sku']); ?></strong></td><td><?= e($p['name']); ?><small class="muted-line">Unité : <?= e($p['unit']); ?></small></td><td><?= e($p['category_name'] ?? 'Sans catégorie'); ?></td><td class="text-right"><?= money($p['cost_price']); ?></td><td class="text-right"><?= money($p['sale_price']); ?></td><td class="text-right"><?= e($p['stock_quantity']); ?></td><td><span class="badge <?= status_badge_class($p['status']); ?>"><?= e(status_label($p['status'])); ?></span></td></tr><?php endforeach; ?></tbody></table></div></section>
